# MinHash LSH for near-deduplication at scale
import hashlib

def minhash_shingles(text, k=5, bands=10):
    shingles = set(text[i:i+k] for i in range(len(text)-k+1))
    hashes = [hashlib.md5(s.encode()).hexdigest() for s in shingles]
    min_hashes = [min(hashes[i::bands]) for i in range(bands)]
    return tuple(min_hashes)

def dedup_corpus(documents, threshold=0.7):
    buckets = {}
    for doc_id, doc in enumerate(documents):
        sig = minhash_shingles(doc)
        for band_idx, h in enumerate(sig):
            key = (band_idx, h)
            buckets.setdefault(key, set()).add(doc_id)
    dup_pairs = set()
    for bucket in buckets.values():
        for i in bucket:
            for j in bucket:
                if i < j:
                    dup_pairs.add((i, j))
    return dup_pairs

# Data mixing experiment framework
import numpy as np

def evaluate_data_mix(mix_proportions, proxy_results):
    target_benchmarks = ['mmlu', 'humaneval', 'gsm8k', 'hellaswag', 'arc']
    scores = {}
    for b in target_benchmarks:
        domain_scores = [proxy_results[d].get(b, 0) for d in mix_proportions]
        scores[b] = np.average(domain_scores, weights=list(mix_proportions.values()))
    return scores

mixes = [
