# Predict loss from scaling law
def predict_loss(N, D, E=1.7, A=400, B=400, alpha=0.34, beta=0.34):
    return E + A / (N ** alpha) + B / (D ** beta)

candidates = [
    (7e9, 15e12, "Llama 3 8B style"),
    (30e9, 3.3e12, "Chinchilla optimal"),
    (70e9, 1.4e12, "Llama 2 70B style"),
]
for N, D, name in candidates:
    loss = predict_loss(N, D)
    gflops = 6 * N * D
    print(f"{name:30s}: loss={loss:.3f}, compute={gflops:.2e} FLOP")
